<script setup lang="ts">
import { computed, ref, watch } from 'vue'

const props = defineProps<{
  src?: string | null
  alt?: string
}>()

const isBroken = ref(false)

watch(
  () => props.src,
  () => {
    isBroken.value = false
  },
)

const hasImage = computed(() => Boolean(props.src) && !isBroken.value)

const onImageError = () => {
  isBroken.value = true
}
</script>

<template>
  <div class="profile-avatar" role="img" :aria-label="props.alt ?? 'Аватар пользователя'">
    <img
      v-if="hasImage"
      class="profile-avatar__image"
      :src="props.src ?? undefined"
      :alt="props.alt ?? 'Аватар пользователя'"
      @error="onImageError"
    />

    <svg
      v-else
     width="160" height="160" viewBox="0 0 160 160" fill="none" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
  <circle cx="80" cy="80" r="79" fill="url(#pattern0_130_264)" stroke="#010307" stroke-width="2" />
  <defs>
    <pattern id="pattern0_130_264" patternContentUnits="objectBoundingBox" width="1" height="1">
      <use xlink:href="#image0_130_264" transform="translate(-0.25102) scale(0.00204082)" />
    </pattern>
    <image id="image0_130_264" width="736" height="490" preserveAspectRatio="none" xlink:href="data:image/jpeg;base64," />
  </defs>
    </svg>
  </div>
</template>

<style lang="scss" scoped>
